mapper.select:
SELECT t.id, t.transfer_no, t.patient_id, p.patient_name, t.ward_id, w.ward_name, t.old_cert_id, t.old_cert_no, t.old_person_id, t.old_person_name, t.new_cert_id, t.new_cert_no, t.new_person_id, t.new_person_name, t.handover_reason, t.operator_id, t.operator_name, t.transfer_time, t.new_apply_status, t.new_audit_user_name, t.new_audit_time, t.new_audit_remark FROM cert_transfer_record t LEFT JOIN patient p ON t.patient_id = p.id LEFT JOIN ward w ON t.ward_id = w.id WHERE t.deleted = 0
AND t.patient_id = #{patientId}
AND t.ward_id = #{wardId}
AND t.old_person_name LIKE CONCAT('%', #{oldPersonName}, '%')
AND t.new_person_name LIKE CONCAT('%', #{newPersonName}, '%')
ORDER BY t.transfer_time DESC
